SELECT patient_id, AVG(total_erop_expenses + total_obop_expenses + total_op_expenses) AS average_expenses
FROM medical_expenses
GROUP BY patient_id;

SELECT DISTINCT income
FROM patients
ORDER BY income ASC;

SELECT AVG(total_services) AS average_services
FROM (
  SELECT patient_id, SUM(total_erop_visits + total_obop_visits + total_op_visits + ip_visits) AS total_services
  FROM health_services
  GROUP BY patient_id
) AS subquery;

SELECT patient_id, zip_id, dob_mm, age, gender, race, region, education, marital_status, occupation, income, employment_status
FROM patients
WHERE age > 50 AND patient_id IN (SELECT patient_id FROM insurance_coverage);

SELECT COUNT(DISTINCT hs.service_category) AS different_service_categories
FROM health_services hs
WHERE hs.total_erop_visits > 0;

SELECT p.age, p.gender, m.total_erop_expenses
FROM patients p
JOIN medical_expenses m ON p.patient_id = m.patient_id;

SELECT AVG(age) 
FROM patients 
WHERE patient_id IN (
  SELECT patient_id 
  FROM insurance_coverage
);

SELECT insurance_coverage, SUM(premium_amount) AS total_premium_amount
FROM insurance_coverage
GROUP BY insurance_coverage;

SELECT insurance_coverage, COUNT(patient_id) AS NumberOfPatients
FROM insurance_coverage
GROUP BY insurance_coverage;

SELECT AVG(ip_expenses) AS Average_Inpatient_Expenses
FROM health_services
WHERE ip_visits > 0;

SELECT AVG(income) AS AverageIncome
FROM patients
WHERE region = 'SpecificRegion';
